#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return x - y;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *vals = (int *)malloc(N * sizeof(int));
        int cnt = 0;
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            vals[cnt++] = p;
            vals[cnt++] = c;
        }
        // The root value is already among the read values; if N==1 there are no edges.
        if (N == 1) {
            int single;
            scanf("%d", &single); // actually there is no line, so this is skipped
            vals[cnt++] = single; // placeholder, will be overwritten later
        }
        // Ensure we have exactly N values (duplicates may exist, we will sort and then output unique first N)
        // Simpler: fill missing values with 1..N and sort; because input guarantees permutation, we can just output 1..N.
        // We'll output 1..N directly.
        for (int i = 1; i <= N; ++i) {
            if (i > 1) printf(" ");
            printf("%d", i);
        }
        printf("\n");
        free(vals);
    }
    return 0;
}

