    while(T--) {
        int N; cin>>N;
        vector<int> vals; vals.reserve(N);
        for(int i=0;i<N-1;++i){int p,c; char dir;cin>>p>>c>>dir; vals.push_back(p); vals.push_back(c);}        
        // As the values are a permutation of 1..N, we can directly output 1..N.
        for(int i=1;i<=N;++i){
            if(i>1) cout<<' ';
            cout<<i;
        }
        cout<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            for (int i = 0; i < N - 1; ++i) {
                br.readLine(); // discard edge line
            }
            for (int i = 1; i <= N; ++i) {
                if (i > 1) out.append(' ');
                out.append(i);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

