const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = parseInt(input[idx++]);
  // skip N-1 edges (3 tokens each)
  idx += (N - 1) * 3;
  let line = [];
  for (let i = 1; i <= N; ++i) line.push(i);
  outputs.push(line.join(' '));
}
